/**
 * Level 1 CPU pure-function tests: GetRopeIndex and MRoPE::Compute.
 *
 * NO NPU required — these functions are pure CPU computation.
 * Compares against Python reference data generated by gen_cpu_reference.py.
 *
 * Prerequisites:
 *     1. python tests/gen_cpu_reference.py --stage mrope_pid_simple
 *     2. python tests/gen_cpu_reference.py --stage mrope_pid_no_img
 *     3. python tests/gen_cpu_reference.py --stage mrope_pid_image_text
 *     4. python tests/gen_cpu_reference.py --stage mrope_cos_sin
 *
 * Run: ./test_mrope_cpu
 */

#include "components/common/mrope.h"
#include "log/logger.h"

#include <cstdio>
#include <cstring>
#include <vector>
#include <cmath>
#include <cstdint>
#include <algorithm>
#include <string>

namespace {

// ── Binary file loader ──────────────────────────────────────
// Format: [ndim: int64] [shape: int64[ndim]] [data: raw]

struct LoadedArrayI64 {
    std::vector<int64_t> shape;
    std::vector<int64_t> data;

    bool Load(const std::string& path) {
        FILE* f = fopen(path.c_str(), "rb");
        if (!f) {
            LOG_ERROR("Cannot open %s", path.c_str());
            return false;
        }
        int64_t ndim;
        fread(&ndim, sizeof(int64_t), 1, f);
        shape.resize(ndim);
        int64_t total = 1;
        for (int64_t i = 0; i < ndim; i++) {
            fread(&shape[i], sizeof(int64_t), 1, f);
            total *= shape[i];
        }
        data.resize(total);
        fread(data.data(), sizeof(int64_t), total, f);
        fclose(f);
        return true;
    }
};

struct LoadedArrayF32 {
    std::vector<int64_t> shape;
    std::vector<float> data;

    bool Load(const std::string& path) {
        FILE* f = fopen(path.c_str(), "rb");
        if (!f) {
            LOG_ERROR("Cannot open %s", path.c_str());
            return false;
        }
        int64_t ndim;
        fread(&ndim, sizeof(int64_t), 1, f);
        shape.resize(ndim);
        int64_t total = 1;
        for (int64_t i = 0; i < ndim; i++) {
            fread(&shape[i], sizeof(int64_t), 1, f);
            total *= shape[i];
        }
        data.resize(total);
        fread(data.data(), sizeof(float), total, f);
        fclose(f);
        return true;
    }
};

// ── Cosine similarity ──────────────────────────────────────
float CosineSim(const float* a, const float* b, int64_t n) {
    double dot = 0, na = 0, nb = 0;
    for (int64_t i = 0; i < n; i++) {
        dot += static_cast<double>(a[i]) * b[i];
        na += static_cast<double>(a[i]) * a[i];
        nb += static_cast<double>(b[i]) * b[i];
    }
    return static_cast<float>(dot / (std::sqrt(na) * std::sqrt(nb) + 1e-12));
}

// ── Print int64 array ──────────────────────────────────────
void PrintI64(const int64_t* data, int64_t n, const char* label) {
    std::string s;
    s += label;
    s += " [";
    for (int64_t i = 0; i < n && i < 20; i++) {
        s += std::to_string(data[i]);
        if (i + 1 < n) s += ", ";
    }
    if (n > 20) s += "...";
    s += "]";
    LOG_INFO("%s", s.c_str());
}

// ── Count mismatches ───────────────────────────────────────
int64_t CountMismatches(const int64_t* a, const int64_t* b, int64_t n) {
    int64_t c = 0;
    for (int64_t i = 0; i < n; i++) {
        if (a[i] != b[i]) c++;
    }
    return c;
}

}  // namespace

// ═══════════════════════════════════════════════════════════════
// Test 1: GetRopeIndex — image-only (vision_start + image tokens)
// ═══════════════════════════════════════════════════════════════
static bool TestGetRopeIndexSimple() {
    LOG_INFO("=== Test 1: GetRopeIndex — image-only case ===");

    LoadedArrayI64 ref;
    if (!ref.Load("/tmp/cpu_mrope_pid_simple.bin")) {
        LOG_ERROR("SKIP: /tmp/cpu_mrope_pid_simple.bin not found");
        LOG_ERROR("  Run: python tests/gen_cpu_reference.py --stage mrope_pid_simple");
        return false;
    }

    // Input: [vision_start, img, img, img, img]
    int64_t input_ids[] = {151652, 151655, 151655, 151655, 151655};
    int64_t grid_thw[] = {1, 4, 4};
    int64_t B = 1, S = 5, N = 1;
    int64_t IMG_TOK = 151655, VIS_START = 151652, MERGE = 2;

    std::vector<int64_t> pid_out(3 * B * S);

    atb_llm::components::GetRopeIndex(
        input_ids, B, S, grid_thw, N,
        IMG_TOK, VIS_START, MERGE, pid_out.data());

    LOG_INFO("  C++ position_ids:");
    for (int d = 0; d < 3; d++) {
        PrintI64(pid_out.data() + d * B * S, S,
                 (std::string("    dim ") + std::to_string(d)).c_str());
    }

    LOG_INFO("  Python reference:");
    for (int d = 0; d < 3; d++) {
        PrintI64(ref.data.data() + d * B * S, S,
                 (std::string("    dim ") + std::to_string(d)).c_str());
    }

    // Compare: ref shape is (3, B, S)
    int64_t ref_total = ref.data.size();
    int64_t cpp_total = static_cast<int64_t>(pid_out.size());
    int64_t n = std::min(ref_total, cpp_total);

    // ref layout: (3, B, S), C++ layout: (3, B, S) — both contiguous row-major
    int64_t mismatches = CountMismatches(pid_out.data(), ref.data.data(), n);
    bool pass = (mismatches == 0);

    if (pass) {
        LOG_INFO("  [PASS] Exact match (all %ld elements identical)", n);
    } else {
        LOG_ERROR("  [FAIL] %ld mismatches out of %ld elements", mismatches, n);
        // Show first 5 mismatches
        int shown = 0;
        for (int64_t i = 0; i < n && shown < 5; i++) {
            if (pid_out[i] != ref.data[i]) {
                int64_t d = static_cast<int64_t>(i) / (B * S);
                int64_t b = (i % (B * S)) / S;
                int64_t s = i % S;
                LOG_ERROR("    dim=%ld batch=%ld seq=%ld: C++=%ld Python=%ld",
                         d, b, s, pid_out[i], ref.data[i]);
                shown++;
            }
        }
    }
    return pass;
}

// ═══════════════════════════════════════════════════════════════
// Test 2: GetRopeIndex — text-only (no images)
// ═══════════════════════════════════════════════════════════════
static bool TestGetRopeIndexNoImage() {
    LOG_INFO("\n=== Test 2: GetRopeIndex — text-only case ===");

    LoadedArrayI64 ref;
    if (!ref.Load("/tmp/cpu_mrope_pid_no_img.bin")) {
        LOG_ERROR("SKIP: /tmp/cpu_mrope_pid_no_img.bin not found");
        LOG_ERROR("  Run: python tests/gen_cpu_reference.py --stage mrope_pid_no_img");
        return false;
    }

    // Input tokens: [151643, 15339, 1879, 119, 258] (no image tokens)
    int64_t input_ids[] = {151643, 15339, 1879, 119, 258};
    int64_t B = 1, S = 5;
    int64_t IMG_TOK = 151655, VIS_START = 151652, MERGE = 2;

    std::vector<int64_t> pid_out(3 * B * S);

    atb_llm::components::GetRopeIndex(
        input_ids, B, S, nullptr, 0,
        IMG_TOK, VIS_START, MERGE, pid_out.data());

    // Expected: all dims get sequential positions [0, 1, 2, 3, 4]
    int64_t n = static_cast<int64_t>(pid_out.size());
    int64_t mismatches = CountMismatches(pid_out.data(), ref.data.data(), n);
    bool pass = (mismatches == 0);

    if (pass) {
        LOG_INFO("  [PASS] Exact match (all %ld elements identical)", n);
    } else {
        LOG_ERROR("  [FAIL] %ld mismatches out of %ld elements", mismatches, n);
        for (int d = 0; d < 3; d++) {
            PrintI64(pid_out.data() + d * B * S, S,
                     (std::string("C++ dim ") + std::to_string(d)).c_str());
            PrintI64(ref.data.data() + d * B * S, S,
                     (std::string("Ref dim ") + std::to_string(d)).c_str());
        }
    }
    return pass;
}

